class Solution:
    def findItinerary(self, tickets):
        from collections import defaultdict
        adj = defaultdict(list)
        for a, b in sorted(tickets, reverse=True):
            adj[a].append(b)
        route = []
        stack = ['JFK']
        while stack:
            while adj[stack[-1]]:
                stack.append(adj[stack[-1]].pop())
            route.append(stack.pop())
        return route[::-1]

